        // Mock sort implementation
        if (sortBy === 'Newest') res.reverse();
        if (sortBy === 'Sponsored First') {
            res.sort((a, b) => (b.isCustomSponsor ? 1 : 0) - (a.isCustomSponsor ? 1 : 0));
